// ─── FlowPulse Reporter Node ───────────────────────────────
// Add this node at the END of any workflow you want to monitor.
// It sends execution data to your FlowPulse dashboard.
//
// CONFIGURE:
//   1. Replace WORKER_URL with your Cloudflare Worker URL
//   2. Replace WORKFLOW_NAME with this workflow's name
//   3. Set STATUS to 'success' (use error handler for failures)

const WORKER_URL    = 'https://flowpulse.yourname.workers.dev';
const WORKFLOW_NAME = 'My Workflow Name';  // ← change this
const WORKFLOW_ID   = $workflow.id;

// Calculate duration
const startedAt  = new Date($execution.startedAt);
const finishedAt = new Date();
const durationMs = finishedAt - startedAt;

// Count items processed (from previous node output)
let itemsProcessed = 0;
try {
  const prevItems = $input.all();
  itemsProcessed = prevItems.length;
} catch(e) {}

// Build payload
const payload = {
  workflowName:   WORKFLOW_NAME,
  workflowId:     WORKFLOW_ID,
  status:         'success',
  startedAt:      startedAt.toISOString(),
  finishedAt:     finishedAt.toISOString(),
  durationMs:     durationMs,
  itemsProcessed: itemsProcessed,
  errorMessage:   null,
  failedNode:     null,
};

// Send to FlowPulse
const response = await fetch(WORKER_URL + '/webhook', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(payload),
});

const result = await response.json();
console.log('FlowPulse:', result);

return [{ json: { flowpulse: result, payload } }];

// ─── FlowPulse Error Reporter ──────────────────────────────
// Add this node as an ERROR HANDLER on your workflow.
// In n8n: Settings → Error Workflow → select this workflow
// OR connect it via the error output of nodes.

const WORKER_URL    = 'https://flowpulse.yourname.workers.dev';
const WORKFLOW_NAME = 'My Workflow Name';  // ← change this

// Get error details from n8n error execution data
let errorMessage = 'Unknown error';
let failedNode   = 'Unknown node';

try {
  const errorData = $input.first()?.json;
  errorMessage = errorData?.error?.message || errorData?.message || 'Execution failed';
  failedNode   = errorData?.execution?.lastNodeExecuted || errorData?.lastNodeExecuted || 'Unknown';
} catch(e) {}

const now = new Date();

const payload = {
  workflowName:   WORKFLOW_NAME,
  workflowId:     $workflow.id,
  status:         'error',
  startedAt:      new Date($execution.startedAt).toISOString(),
  finishedAt:     now.toISOString(),
  durationMs:     now - new Date($execution.startedAt),
  itemsProcessed: 0,
  errorMessage:   errorMessage,
  failedNode:     failedNode,
};

const response = await fetch(WORKER_URL + '/webhook', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(payload),
});

const result = await response.json();
console.log('FlowPulse Error Report:', result);

return [{ json: { flowpulse: result } }];
